const login = async () => {
  if (!email || !password) {
    alert("Please fill all fields ⚠️");
    return;
  }

  try {
    setLoading(true);

    const res = await api.post("/auth/login", {
      email,
      password
    });

    const { token, role } = res.data;

    // ================= SAVE DATA =================
    localStorage.setItem("token", token);
    localStorage.setItem("role", role);

    alert("Login Successful 🎉");

    // ================= ROLE REDIRECT =================
    if (role === "ROLE_ADMIN") {
      navigate("/admin");
    } else {
      navigate("/dashboard");
    }

  } catch (error) {
    console.log(error);
    alert("Invalid credentials ❌");
  } finally {
    setLoading(false);
  }
};
